import React, { useState, useEffect } from 'react';
import {
  Box,
  CssBaseline,
  ThemeProvider,
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  IconButton,
  useMediaQuery,
  Typography,
  Container,
  Menu,
  MenuItem,
} from '@mui/material';
import { BrowserRouter as Router, Routes, Route, Navigate, useLocation, Link } from 'react-router-dom';
import getTheme from './theme';
import ErrorBoundary from './components/ErrorBoundary';

// Import your components
import Dashboard from './pages/Dashboard';
import Nodes from './pages/Nodes';
import Rules from './pages/Rules';
import Settings from './pages/Settings';
import Subscriptions from './pages/Subscriptions';

import {
  Dashboard as DashboardIcon,
  Dns as DnsIcon,
  Settings as SettingsIcon,
  Rule as RuleIcon,
  Menu as MenuIcon,
} from '@mui/icons-material';

const drawerWidth = 150;

const menuItems = [
  { text: '仪表盘', icon: <DashboardIcon />, path: '/' },
  { text: '节点管理', icon: <DnsIcon />, path: '/nodes' },
  { text: '规则管理', icon: <RuleIcon />, path: '/rules' },
  { text: '订阅管理', icon: <DnsIcon />, path: '/subscriptions' },
  { text: '系统设置', icon: <SettingsIcon />, path: '/settings' },
];

function App() {
  const [mode, setMode] = useState(() => {
    const savedMode = localStorage.getItem('themeMode');
    return savedMode || 'light';
  });
  const [mobileOpen, setMobileOpen] = useState(false);
  const [dashboardAnchorEl, setDashboardAnchorEl] = useState(null);
  const theme = getTheme(mode);

  useEffect(() => {
    localStorage.setItem('themeMode', mode);
  }, [mode]);

  return (
    <ThemeProvider theme={theme}>
      <ErrorBoundary>
        <Router>
          <Routes>
            <Route
              path="/*"
              element={
                <AppContent 
                  mode={mode} 
                  setMode={setMode}
                  mobileOpen={mobileOpen}
                  setMobileOpen={setMobileOpen}
                  dashboardAnchorEl={dashboardAnchorEl}
                  setDashboardAnchorEl={setDashboardAnchorEl}
                />
              }
            />
          </Routes>
        </Router>
      </ErrorBoundary>
    </ThemeProvider>
  );
}

function AppContent({ mode, setMode, mobileOpen, setMobileOpen, dashboardAnchorEl, setDashboardAnchorEl }) {
  const isMobile = useMediaQuery((theme) => theme.breakpoints.down('sm'));
  const location = useLocation();

  const handleDrawerToggle = () => {
    setMobileOpen(!mobileOpen);
  };

  const handleDashboardClick = (event) => {
    setDashboardAnchorEl(event.currentTarget);
  };

  const handleDashboardClose = () => {
    setDashboardAnchorEl(null);
  };

  const handleDashboardSelect = (url) => {
    window.open(url, '_blank');
    handleDashboardClose();
  };

  const drawer = (
    <Box>
      <Box sx={{ 
        p: 2, 
        display: 'flex', 
        alignItems: 'center', 
        gap: 1,
        pl: 2.5
      }}>
        <Typography 
          variant="h6" 
          noWrap 
          component="div"
          sx={{ 
            fontSize: '1.2rem',
            fontWeight: 600,
            color: (theme) => theme.palette.primary.main
          }}
        >
          singdns
        </Typography>
      </Box>
      <List sx={{ mt: 1 }}>
        {menuItems.map((item) => (
          <ListItem
            button
            key={item.text}
            component={Link}
            to={item.path}
            selected={location.pathname === item.path}
            onClick={() => isMobile && handleDrawerToggle()}
            sx={{
              minHeight: 40,
              px: 2.5,
              py: 0.75,
              '&.Mui-selected': {
                backgroundColor: (theme) => 
                  theme.palette.mode === 'dark' 
                    ? 'rgba(255, 255, 255, 0.08)'
                    : 'rgba(0, 0, 0, 0.04)',
                '&:hover': {
                  backgroundColor: (theme) => 
                    theme.palette.mode === 'dark' 
                      ? 'rgba(255, 255, 255, 0.12)'
                      : 'rgba(0, 0, 0, 0.08)',
                },
              },
            }}
          >
            <ListItemIcon 
              sx={{ 
                minWidth: 32,
                color: (theme) => 
                  location.pathname === item.path
                    ? theme.palette.primary.main
                    : theme.palette.text.secondary,
              }}
            >
              {item.icon}
            </ListItemIcon>
            <ListItemText 
              primary={item.text}
              primaryTypographyProps={{
                fontSize: '0.875rem',
                fontWeight: location.pathname === item.path ? 500 : 400,
                color: (theme) => 
                  location.pathname === item.path
                    ? theme.palette.text.primary
                    : theme.palette.text.secondary,
              }}
            />
          </ListItem>
        ))}
      </List>
    </Box>
  );

  return (
    <Box sx={{ display: 'flex', minHeight: '100vh' }}>
      <CssBaseline />

      <Box
        component="nav"
        sx={{
          width: { sm: drawerWidth },
          flexShrink: { sm: 0 }
        }}
      >
        {isMobile && (
          <IconButton
            color="inherit"
            aria-label="open drawer"
            edge="start"
            onClick={handleDrawerToggle}
            sx={{ mr: 2, display: { sm: 'none' } }}
          >
            <MenuIcon />
          </IconButton>
        )}
        <Drawer
          variant={isMobile ? 'temporary' : 'permanent'}
          open={isMobile ? mobileOpen : true}
          onClose={handleDrawerToggle}
          ModalProps={{
            keepMounted: true,
          }}
          sx={{
            '& .MuiDrawer-paper': {
              boxSizing: 'border-box',
              width: drawerWidth,
            },
          }}
        >
          {drawer}
        </Drawer>
      </Box>

      <Box
        component="main"
        sx={{
          flexGrow: 1,
          width: { sm: `calc(100% - ${drawerWidth}px)` },
          ml: { sm: `${drawerWidth}px` },
          backgroundColor: (theme) => theme.palette.background.default,
          minHeight: '100vh',
        }}
      >
        <Container 
          maxWidth={false} 
          sx={{ 
            py: 1,
            px: { xs: 1, sm: 1.5 },
            height: '100%',
          }}
        >
          <Menu
            anchorEl={dashboardAnchorEl}
            open={Boolean(dashboardAnchorEl)}
            onClose={handleDashboardClose}
            PaperProps={{
              elevation: 0,
              sx: {
                border: '1px solid',
                borderColor: (theme) => 
                  theme.palette.mode === 'dark' 
                    ? 'rgba(255, 255, 255, 0.12)'
                    : 'rgba(0, 0, 0, 0.06)',
              },
            }}
          >
            <MenuItem onClick={() => handleDashboardSelect('/ui/metacubexd/')}>
              MetaCubeXD
            </MenuItem>
            <MenuItem onClick={() => handleDashboardSelect('/ui/yacd/')}>
              YACD
            </MenuItem>
          </Menu>
          <Routes>
            <Route path="/" element={
              <Dashboard 
                mode={mode} 
                setMode={setMode}
                onDashboardClick={handleDashboardClick}
              />
            } />
            <Route path="/nodes" element={<Nodes />} />
            <Route path="/rules" element={<Rules />} />
            <Route path="/subscriptions" element={<Subscriptions />} />
            <Route path="/settings" element={<Settings />} />
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </Container>
      </Box>
    </Box>
  );
}

export default App;
